const incoming = $json.body || $json;
const message = incoming.message || {};
const content = message.content || message.raw_content || incoming.content || incoming.body?.message?.content || incoming.body?.content;
const stream = incoming.stream || message.stream || incoming.body?.stream;
const subject = incoming.subject || message.subject || incoming.body?.subject || (stream ? 'general' : undefined);
const sender_email = incoming.sender_email || message.sender_email || incoming.body?.sender_email || (message.type === 'private' ? message.sender_email : undefined);

if (!content) {
  throw new Error('Missing message content');
}

return [{
  json: {
    content,
    stream,
    subject,
    sender_email,
    message: {
      content,
      type: stream ? 'stream' : 'private',
      sender_email,
      stream,
      subject
    }
  }
}];
